import{_ as e,o as p,c as t,ag as i}from"./chunks/framework.ePeAWSvT.js";const r="/images/image_235.png",n="/images/image_236.png",o="/images/image_237.png",s="/images/image_238.png",g="/images/image_239.png",m="/images/image_240.png",c="/images/image_241.png",l="/images/image_242.png",d="/images/image_243.png",h="/images/image_244.png",I=JSON.parse('{"title":"诊断","description":"","frontmatter":{},"headers":[],"relativePath":"guide/diagnosis/index.md","filePath":"guide/diagnosis/index.md","lastUpdated":1772677403000}'),_={name:"guide/diagnosis/index.md"};function u(P,a,b,T,q,f){return p(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="诊断" tabindex="-1">诊断 <a class="header-anchor" href="#诊断" aria-label="Permalink to &quot;诊断&quot;">​</a></h1><h2 id="网络工具" tabindex="-1">网络工具 <a class="header-anchor" href="#网络工具" aria-label="Permalink to &quot;网络工具&quot;">​</a></h2><h3 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h3><p>Ping</p><p>通过使用 ping 工具，用户可以检查指定 IP 地址的设备是否可达，测试网络连接是否出现故障。ping 的成功执行过程为：</p><p>(1) 源设备向目的设备发送 ICMP 回显请求（ ECHO-REQUEST）报文。</p><p>(2) 目的设备在接收到该请求报文后，向源设备发送 ICMP 回显应答（ ECHO-REPLY）报文。</p><p>(3) 源设备在收到该应答报文后，显示相关的统计信息。</p><p>ping 的输出信息分为以下几种情况：</p><p>• ping 的执行对象可以是目的设备的 IP 地址或者主机名，如果该目的设备的主机名不可识别，则源设备上输出提示信息。</p><p>• 如果在超时时间内源设备没有收到目的设备回的 ICMP 回显应答报文，则输出提示信息和ping 过程报文的统计信息；如果在超时时间内源设备收到响应报文，则输出响应报文的字节数、报文序号、 TTL（Time to Live，生存时间）、响应时间和 ping 过程报文的统计信息。ping 过程报文的统计信息包括发送报文个数、接收到响应报文个数、未响应报文数百分比、响应时间的最小值、平均值和最大值。</p><p>Trace route</p><p>通过使用 trace route 工具，用户可以查看报文从源设备传送到目的设备所经过的三层设备。当网络出现故障时，用户可以使用该命令分析出现故障的网络节点。trace route 的执行过程为：</p><p>(1) 源设备发送一个 TTL 为 1 的报文给目的设备。</p><p>(2) 第一跳（即该报文所到达的第一个三层设备）回应一个 TTL 超时的 ICMP 报文（该报文中含有第一跳的 IP 地址），这样源设备就得到了第一个三层设备的地址。</p><p>(3) 源设备重新发送一个 TTL 为 2 的报文给目的设备。</p><p>(4) 第二跳回应一个 TTL 超时的 ICMP 报文，这样源设备就得到了第二个三层设备的地址。</p><p>(5) 以上过程不断进行，直到最终到达目的设备，源设备就得到了从它到目的设备所经过的所有三层设备的地址。</p><p>trace route 的执行对象可以是目的设备的 IP 地址或者主机名，如果该目的设备的主机名不可识别，</p><p>则源设备上输出提示信息。</p><h3 id="ping和trace-route操作" tabindex="-1">ping和trace route操作 <a class="header-anchor" href="#ping和trace-route操作" aria-label="Permalink to &quot;ping和trace route操作&quot;">​</a></h3><p>Ping操作</p><p>（1）在导航栏中选择【诊断】【网络工具】，进入ping/trace route页面，如图6-1所示。在ping操作IP地址栏输入需要ping的IP地址，点击【应用】按钮。</p><p><img src="'+r+'" alt="ping操作界面"></p><p align="center"><em>图6-1 ping操作界面</em></p><p>（2）在下方的信息框中查看ping操作的返回结果，如图6-2所示。</p><p><img src="'+n+'" alt="ping操作返回结果"></p><p align="center"><em>图6-2 ping操作返回结果</em></p><p>Trace route操作</p><p>（1）在导航栏中选择【诊断】【网络工具】，进入ping/trace route页面，如图6-3所示。在ping操作IP地址栏输入需要ping的IP地址，点击【应用】按钮。</p><p><img src="'+o+'" alt="trace route操作界面"></p><p align="center"><em>图6-3 trace route操作界面</em></p><p>（2）在下方的信息框中查看ping操作的返回结果，如图6-4所示。</p><p><img src="'+s+'" alt="trace route操作返回结果"></p><p align="center"><em>图6-4 trace route操作返回结果</em></p><h2 id="光模块信息" tabindex="-1">光模块信息 <a class="header-anchor" href="#光模块信息" aria-label="Permalink to &quot;光模块信息&quot;">​</a></h2><p>在导航栏中选择【诊断】【光模块信息】，进入光模块信息监控页面。如图6-5所示，可以查询光模块的数字诊断信息。</p><p><img src="'+g+'" alt="光模块数字诊断信息"></p><p align="center"><em>图6-5 光模块数字诊断信息</em></p><p>点击【详细】按钮，可以查询光模块的供应商，序列号，生产日期等基本信息，如图6-6所示。</p><p><img src="'+m+'" alt="光模块基本信息"></p><p align="center"><em>图6-6 光模块基本信息</em></p><h2 id="一键收集" tabindex="-1">一键收集 <a class="header-anchor" href="#一键收集" aria-label="Permalink to &quot;一键收集&quot;">​</a></h2><p>因为各个功能模块都有其对应的运行信息，所以一般情况下，用户需要逐个模块查看显示信息。为了在日常维护或系统出现故障时能够一次性收集更多信息，设备支持诊断信息模块。用户执行生成诊断信息文件的操作时，系统会将当前多个功能模块运行的统计信息保存在一个名为“backup-SWITCH-year-mon-day</p><p>-log”的文件中，用户可以通过查看该文件来更快的定位问题。</p><p>步骤1：在导航栏中选择【诊断】【一键收集】。</p><p>步骤2：单击【一键收集】按钮，弹出“文件下载”对话框，将日志文件保存到本地。</p><p><img src="'+c+'" alt="光模块基本信息"></p><p align="center"><em>图6-7 光模块基本信息</em></p><h2 id="掉电告警" tabindex="-1">掉电告警 <a class="header-anchor" href="#掉电告警" aria-label="Permalink to &quot;掉电告警&quot;">​</a></h2><h3 id="概述-1" tabindex="-1">概述 <a class="header-anchor" href="#概述-1" aria-label="Permalink to &quot;概述&quot;">​</a></h3><p>Dying-gasp功能为断掉设备供电瞬间，依靠设备内部电容等储能器件供电10-20ms时间，支持设备发出掉电告警信息。</p><p>根据802.3ah中定义，当发生设备掉电事件后，设备向其连接设备发出OAM事件报文，由于OAM为点到点协议，掉电事件报文在送达到下一个支持OAM的设备后，不再继续转发。接收到掉电事件的设备将输出掉电LOG提示信息。</p><p>除OAM告警信息，掉电设备还将发出一条trap信息到smmp服务器。</p><table tabindex="0"><thead><tr><th>节点信息</th><th>数据</th></tr></thead><tbody><tr><td>Mib files</td><td>DOT3-OAM-MIB.mib</td></tr><tr><td>oid</td><td>1, 3, 6, 1, 2, 1, 158, 1, 6, 1, 4</td></tr><tr><td>value</td><td>dyingGaspEvent(257)</td></tr></tbody></table><h3 id="配置掉电告警" tabindex="-1">配置掉电告警 <a class="header-anchor" href="#配置掉电告警" aria-label="Permalink to &quot;配置掉电告警&quot;">​</a></h3><p>在导航栏中选择【诊断】【掉电告警】，进入Dying Gasp掉电告警页面，如图6-8所示，点击启用/禁用下的按钮来使能或关闭Dying Gasp功能，此功能默认情况下为关闭状态。</p><p><img src="'+l+'" alt="Dying Gasp配置界面"></p><p align="center"><em>图6-8 Dying Gasp配置界面</em></p><h2 id="线缆检测" tabindex="-1">线缆检测 <a class="header-anchor" href="#线缆检测" aria-label="Permalink to &quot;线缆检测&quot;">​</a></h2><p>线缆检测是指，用户可以检测设备上以太网接口连接电缆的当前状况，系统将在 5 秒内返回检测结果。检测内容包括线缆是否存在短路或开路现象以及故障线缆的长度。</p><p>步骤1：在导航栏中选择【诊断】【线缆检测】，进入线缆检测的页面，如图6-9所示。</p><p>步骤2：选择要检测的接口，单击【检测】按钮开始进线检测，系统在 5 秒内返回检测结果。</p><p>步骤3：如图6-10所示，在弹出的页面中查看检测结果。</p><p><img src="'+d+'" alt="线缆检测界面"></p><p align="center"><em>图6-9 线缆检测界面</em></p><p><img src="'+h+'" alt="线缆检测结果"></p><p align="center"><em>图6-10 线缆检测结果</em></p><p>Pair X 长度：单位米，电缆长度，有故障时为接口到故障位置的长度</p><p>Pair X 状态：</p><p>OK（正常）：表示线对（PAIR）正常终结</p><p>Open（开路）：表示线对开路</p><p>Short（短路）：表示线对短路</p><p>Unknown（未知）：其他未知故障原因</p>',74)])])}const k=e(_,[["render",u]]);export{I as __pageData,k as default};
